-	return host
+	// net.SplitHostPort handles "[::1]:port", "host:port", etc.
+	h, _, err := net.SplitHostPort(host)
+	if err != nil {
+		// Not in host:port form — return as-is (bare IPv6 like "::1").
+		return host
+	}
+	return h
